test('cria cobranca como preference do Checkout Pro', async () => {
  const calls = [];
  const mp = new MercadoPago({
    apiKey: 'TOKEN',
    webhookUrl: 'https://site.test/webhook',
    fetch: async (url, options) => {
      calls.push({ url, options });
      return jsonResponse(201, {
        id: 'pref-123',
        external_reference: 'produto-1',
        init_point: 'https://checkout.test/prod',
        sandbox_init_point: 'https://checkout.test/sandbox',
        date_created: '2026-05-15T00:00:00Z'
      });
    }
  });

  const result = await mp.criarCobranca({
    produto: 'Produto Teste',
    id: 'produto-1',
    preco: 49.9
  });

  assert.equal(result.ok, true);
  assert.equal(result.dados.id, 'pref-123');
  assert.equal(result.dados.link, 'https://checkout.test/prod');
  assert.equal(calls[0].url, 'https://api.mercadopago.com/checkout/preferences');

  const payload = JSON.parse(calls[0].options.body);
  assert.equal(payload.notification_url, 'https://site.test/webhook');
  assert.equal(payload.items[0].unit_price, 49.9);
});

