test('acompanha cobranca por loop e remove memoria quando paga', async (t) => {
  const memoryLoopPath = await tempMemoryLoop(t);
  const mp = new MPFacil({
    apiKey: 'TOKEN',
    memoryLoopPath,
    autoResumeLoops: false,
    fetch: async () => jsonResponse(200, {
      id: 321,
      status: 'approved',
      status_detail: 'accredited',
      transaction_amount: 10,
      currency_id: 'BRL',
      external_reference: 'pedido-321',
      metadata: {
        idUser: 'user-321'
      }
    })
  });

  const pago = new Promise((resolve) => mp.once('pago', resolve));
  const loop = await mp.acompanharCobranca(321, { intervaloMs: 10, duracaoMs: 1000 });

  assert.equal(loop.ok, true);
  assert.equal(loop.dados.status, 'monitorando');

  const pagamento = await pago;

  assert.equal(pagamento.situacao, 'pago');
  assert.equal(pagamento.metadados.idUser, 'user-321');
  await assert.rejects(fs.access(path.join(memoryLoopPath, '321.json')), { code: 'ENOENT' });
});

test('retoma loop salvo em memory loop ao iniciar de novo', async (t) => {
  const memoryLoopPath = await tempMemoryLoop(t);
  await fs.writeFile(path.join(memoryLoopPath, '654.json'), JSON.stringify({
    id: '654',
    pagamentoId: '654',
    status: 'monitorando',
    intervaloMs: 10,
    duracaoMs: null,
    criadoEm: new Date().toISOString(),
    iniciadoEmMs: Date.now(),
    terminaEmMs: null,
    tentativas: 0,
    ultimoResultado: null,
    modoTeste: false
  }, null, 2));

  const mp = new MPFacil({
    apiKey: 'TOKEN',
    memoryLoopPath,
    autoResumeLoops: false,
    fetch: async () => jsonResponse(200, {
      id: 654,
      status: 'approved',
      status_detail: 'accredited',
      transaction_amount: 15,
      currency_id: 'BRL',
      external_reference: 'pedido-654'
    })
  });

  const pago = new Promise((resolve) => mp.once('pago', resolve));
  const resumed = await mp.retomarLoops();

  assert.equal(resumed.ok, true);
  assert.equal(resumed.dados.retomados, 1);

  const pagamento = await pago;

  assert.equal(pagamento.referencia, 'pedido-654');
  await assert.rejects(fs.access(path.join(memoryLoopPath, '654.json')), { code: 'ENOENT' });
});

