test('valida assinatura de webhook oficial', () => {
  const secret = 'segredo';
  const dataId = '123456';
  const requestId = 'bb56a2f1';
  const ts = '1742505638683';
  const manifest = `id:${dataId};request-id:${requestId};ts:${ts};`;
  const hash = crypto.createHmac('sha256', secret).update(manifest).digest('hex');
  const mp = new MercadoPago({ apiKey: 'TOKEN', webhookSecret: secret });

  const result = mp.interpretarWebhook({
    body: {
      action: 'payment.updated',
      type: 'payment',
      data: { id: dataId }
    },
    query: { 'data.id': dataId },
    headers: {
      'x-request-id': requestId,
      'x-signature': `ts=${ts},v1=${hash}`
    }
  });

  assert.equal(result.ok, true);
  assert.equal(result.dados.id, dataId);
  assert.equal(result.dados.tipo, 'payment');
});

function jsonResponse(status, body) {
  return {
    ok: status >= 200 && status < 300,
    status,
    text: async () => JSON.stringify(body)
  };
}

async function tempMemoryLoop(t) {
  const directory = await fs.mkdtemp(path.join(os.tmpdir(), 'mp-facil-memory-loop-'));
  t.after(async () => {
    await fs.rm(directory, { recursive: true, force: true });
  });

  return directory;
}
